            ContentJson = """{"title":"Shipments Field Reference","groups":[{"heading":"Shipment Form Fields (Create Dialog — Sidebar)","items":[{"label":"Sales Order (required)","value":"Pick the order this shipment fills. Start typing to find it; each choice shows the order number, customer, and customer PO. This is the only field you must fill on the sidebar."},{"label":"Carrier","value":"Optional. The carrier's name, such as UPS, FedEx, USPS, DHL, or Freight. Shows in the list and on the shipment."},{"label":"Tracking Number","value":"Optional. The tracking number the carrier gives you. Once it's set, you can track the shipment from its detail view."},{"label":"Weight","value":"Optional. The shipment's total weight in pounds."},{"label":"Shipping Cost","value":"Optional. What the shipment costs to send, shown as a dollar amount."},{"label":"Notes","value":"Optional. Anything worth writing down, such as handling or delivery instructions."}]},{"heading":"Line Item Fields (Create Dialog — Main Area)","items":[{"label":"Order Line (required)","value":"Pick one of the sales order's open lines — you don't pick loose parts. Only lines with something still left to ship appear, each showing the part and how much is left. Pick the order first; until then it says 'Select an order first,' and if it's all shipped it says 'All lines shipped.'"},{"label":"Quantity (required)","value":"Fills in with what's left to ship on that line, and won't go higher — try to enter more and it's pulled back to the limit. Must be more than 0."},{"label":"Add button","value":"Adds the line and quantity you picked to the shipment. Stays off until you've picked a line and a valid quantity."},{"label":"Remove button (X)","value":"Takes a line back off the shipment. Each line in the list has a red X to remove it."}]},{"heading":"Shipment Statuses","items":[{"label":"Pending","value":"Where every shipment starts. It's been created but nothing is packed yet. You can mark it shipped, or move it to Packed first."},{"label":"Packed","value":"Items are packed and the shipment is ready to leave. You can mark it shipped from here."},{"label":"Shipped","value":"The shipment has left. The shipped date is filled in for you. You can mark it delivered from here."},{"label":"In Transit","value":"The carrier has it and it's on the way. You can mark it delivered from here, and tracking shows the carrier's updates."},{"label":"Delivered","value":"The customer got it. The delivered date is filled in for you. This is the end of the line — nothing more to do."},{"label":"Cancelled","value":"The shipment was called off before delivery. The record is kept for your history. This is the end of the line — nothing more to do."}]},{"heading":"Detail View Fields (Read-Only)","items":[{"label":"Shipment Number","value":"The shipment's own number, created for you. It sits at the top of the detail view."},{"label":"Customer Name","value":"Comes from the sales order. Shows just under the shipment number."},{"label":"Sales Order","value":"A link you can click to open the sales order. Shows the order number."},{"label":"Carrier","value":"Shows only if you entered a carrier."},{"label":"Tracking Number","value":"Shows only if you entered one. You can use it to track the shipment."},{"label":"Shipped Date","value":"Shows once the shipment is marked shipped."},{"label":"Delivered Date","value":"Shows once the shipment is marked delivered."},{"label":"Weight","value":"Shows only if you entered a weight, in pounds."},{"label":"Shipping Cost","value":"Shows only if you entered a cost, as a dollar amount."},{"label":"Linked Invoice","value":"Shows only once an invoice exists for this shipment. Click it to open the invoice."},{"label":"Notes","value":"Shows only if you added notes."},{"label":"Line Items","value":"A list of what's on the shipment, with a description and quantity for each. The heading shows how many lines there are."},{"label":"Created / Updated dates","value":"When the shipment was made and last changed, at the bottom of the detail view."}]},{"heading":"Buttons and Actions","items":[{"label":"New Shipment (page header)","value":"Opens the window for starting a shipment."},{"label":"Save / Create Shipment","value":"Creates the shipment. Stays off until the form is complete and at least one line is added. Hover over it to see what's still missing."},{"label":"Cancel","value":"Closes the new-shipment window without saving."},{"label":"Mark Shipped","value":"Sets the shipment to Shipped and fills in the shipped date. Available when it's Pending or Packed. Asks you to confirm first."},{"label":"Mark Delivered","value":"Sets the shipment to Delivered and fills in the delivered date. Available when it's Shipped or In Transit. Asks you to confirm first."},{"label":"Get Rates","value":"Opens a window to compare carrier rates. Available when the shipment is Pending or Packed. Shows each carrier's service, price, and estimated delivery."},{"label":"Track","value":"Shows the tracking timeline for the shipment. Available once a tracking number exists and the timeline isn't already open. Lists each event with its place, status, and time."},{"label":"Close Tracking","value":"Hides the tracking timeline again."},{"label":"Row Click","value":"Opens the shipment you click. Shows all its details, lines, tracking, and available actions."}]},{"heading":"Validation Rules","items":[{"label":"Sales Order","value":"Required. You must pick a valid sales order."},{"label":"Line Items","value":"You need at least one line. Until then, Save stays off and a message tells you a line is needed."},{"label":"Order Line (per line)","value":"Required. Each line must come from the sales order's open lines — not a loose part."},{"label":"Quantity (per line)","value":"Required. Must be more than 0 and can't be more than what's left to ship on that line."},{"label":"Carrier, Tracking Number, Weight, Shipping Cost, Notes","value":"All optional, with no set format."},{"label":"Why Save is off","value":"When the form isn't complete or has no lines, hover over Save to see everything that's still missing."}]},{"heading":"Table Columns","items":[{"label":"Shipment #","value":"The shipment's number. Click the heading to sort."},{"label":"SO #","value":"The sales order the shipment fills. Click the heading to sort."},{"label":"Customer","value":"The customer from the sales order. Click the heading to sort."},{"label":"Status","value":"The shipment's status as a colored label — Pending, Packed, Shipped, In Transit, Delivered, or Cancelled. You can sort or filter by it."},{"label":"Carrier","value":"The carrier, or '---' if none is set. Click the heading to sort."},{"label":"Tracking #","value":"The tracking number, or '---' if none is set. Click the heading to sort."},{"label":"Shipped Date","value":"The date it shipped, or '---' if it hasn't yet. Click the heading to sort."},{"label":"Created","value":"The date the shipment was made. Click the heading to sort."}]}]}"""
